'use strict';
/**
 * REGRESSION — FRG-245
 * Character-to-character collision avoidance.
 *
 * Tests run against the local dev server (http://localhost:5175) which serves
 * the feature/frg-245-character-collision-avoidance branch.
 *
 * window._gameEngine is set unconditionally in scene.js create() so no
 * route injection is needed.
 *
 * Actual API (verified against source):
 *   engine._buildDynamicWalkable(excludeChar)      — clones static grid, marks other chars blocked
 *   engine._findAdjacentWalkable(tx, ty, walkable) — returns first free cardinal neighbor
 *   engine._doWander(char)                         — runs wander logic inc. deadlock escape
 *   engine.update(deltaMs)                         — advances one sim tick
 *   char.moveTo(goalTx, goalTy, walkable?)         — A* path on given grid; returns boolean
 *   char._failedMoveCount                          — consecutive wander failures; reset on success
 *   char.wanderTimer                               — ms until next wander attempt
 *   engine.walkable[row][col]                      — static walkable grid (boolean[][])
 *   engine.characters                              — [Maple(Amelia), Sol(Lucy), Nyx(Ash)]
 *   engine.objectEngine.getById(id)                — valid IDs: stove,fridge,tea_set,kotatsu,etc.
 *
 * Walkable grid: 19 cols × 13 rows.
 *   Interior floor: col 1–17, row 2–9 (minus object tiles).
 *   Object tiles (non-walkable): stove(3,3), fridge(2,3), tea_set(5,5), kotatsu(6,6),
 *     tv(9,3), bookshelf(15,3), desk(14,5), bed(16,5), easel(2,7), bonsai(11,8).
 *
 * Test layout:
 *   1. No tile sharing — no two chars idle/interacting on the same tile over 30+ poll samples
 *   2. _buildDynamicWalkable — other chars blocked, own tile walkable, static grid unchanged
 *   3. moveTo with dynamic grid — path routes around a blocking character's tile
 *   4. Deadlock escape — _failedMoveCount resets to 0 after third wander failure
 *   5. Live sim stability — no crashes and all chars become active within 120s sim-time
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:5175';

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Wait for the SimulationEngine to be fully initialised with 3 characters.
 */
async function waitForEngine(page) {
  await page.waitForFunction(
    () => window._gameEngine?.characters?.length === 3,
    { timeout: 15_000 }
  );
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-245: Character Collision Avoidance', () => {

  // ── TEST 1: No tile sharing during idle/interacting ────────────────────────

  test('no two characters share a tile when idle or interacting over 30 poll samples', async ({ page }) => {
    test.setTimeout(120_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    // Let the Phaser game loop run naturally; poll character positions.
    // 30 polls × 300 ms = ~9 real seconds of simulation coverage.
    const violations = [];
    const POLL_COUNT   = 30;
    const POLL_INTERVAL_MS = 300;

    for (let i = 0; i < POLL_COUNT; i++) {
      await page.waitForTimeout(POLL_INTERVAL_MS);

      const charPositions = await page.evaluate(() =>
        window._gameEngine.characters.map(c => ({
          label:  c.label,
          tx:     Math.round(c.tx),
          ty:     Math.round(c.ty),
          action: c.action,
        }))
      );

      // Only check when characters are in a stable state (not mid-walk)
      const stable = charPositions.filter(
        c => c.action === 'idle' || c.action === 'interacting' || c.action === 'talking'
      );

      for (let a = 0; a < stable.length; a++) {
        for (let b = a + 1; b < stable.length; b++) {
          if (stable[a].tx === stable[b].tx && stable[a].ty === stable[b].ty) {
            violations.push({
              poll:    i,
              charA:   stable[a].label,
              charB:   stable[b].label,
              tile:    `(${stable[a].tx},${stable[a].ty})`,
              actions: `${stable[a].action}/${stable[b].action}`,
            });
          }
        }
      }
    }

    if (violations.length > 0) {
      console.error('Tile-sharing violations:', JSON.stringify(violations, null, 2));
    }

    expect(violations.length,
      `Characters shared tiles on ${violations.length} poll(s): ` +
      violations.map(v => `${v.charA}+${v.charB}@${v.tile}`).join(', ')
    ).toBe(0);
  });

  // ── TEST 2: _buildDynamicWalkable correctness ─────────────────────────────

  test('_buildDynamicWalkable marks other chars blocked, preserves own tile, leaves static grid unchanged', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      const solTx   = Math.round(sol.tx);
      const solTy   = Math.round(sol.ty);
      const nyxTx   = Math.round(nyx.tx);
      const nyxTy   = Math.round(nyx.ty);
      const mapleTx = Math.round(maple.tx);
      const mapleTy = Math.round(maple.ty);

      // Build dynamic grid treating all others as obstacles for maple
      const dynWalkable = engine._buildDynamicWalkable(maple);

      return {
        // Other characters' tiles should be blocked in the dynamic grid
        solBlocked:  dynWalkable[solTy]?.[solTx]   === false,
        nyxBlocked:  dynWalkable[nyxTy]?.[nyxTx]   === false,
        // Calling character's own tile must stay walkable
        mapleWalkable: dynWalkable[mapleTy]?.[mapleTx] === true,
        // Static grid must not have been modified
        staticSolTile:   engine.walkable[solTy]?.[solTx]   === true,
        staticNyxTile:   engine.walkable[nyxTy]?.[nyxTx]   === true,
        staticMapleTile: engine.walkable[mapleTy]?.[mapleTx] === true,
        // Sanity: dynamic grid is a separate object (deep clone)
        isDifferentObject: dynWalkable !== engine.walkable,
      };
    });

    console.log('_buildDynamicWalkable result:', JSON.stringify(result));

    expect(result.solBlocked,
      'Sol\'s tile should be blocked in the dynamic grid built for Maple'
    ).toBe(true);

    expect(result.nyxBlocked,
      'Nyx\'s tile should be blocked in the dynamic grid built for Maple'
    ).toBe(true);

    expect(result.mapleWalkable,
      'Maple\'s own tile must remain walkable in the dynamic grid'
    ).toBe(true);

    expect(result.staticSolTile,
      '_buildDynamicWalkable must not modify the static walkable grid (Sol\'s tile)'
    ).toBe(true);

    expect(result.staticNyxTile,
      '_buildDynamicWalkable must not modify the static walkable grid (Nyx\'s tile)'
    ).toBe(true);

    expect(result.isDifferentObject,
      'Dynamic walkable must be a separate array, not the same reference as engine.walkable'
    ).toBe(true);
  });

  // ── TEST 3: moveTo routes around a blocking character's tile ─────────────

  test('moveTo with dynamic walkable avoids the blocking character\'s tile', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const [maple, sol] = engine.characters;

      // Place maple at (1, 2) — walkable left edge, row 2
      maple.tx = 1; maple.ty = 2;
      maple.prevTx = 1; maple.prevTy = 2;
      maple.path = []; maple.moveProgress = 0; maple.action = 'idle';

      // Place sol (blocker) at (6, 2) — directly on the straight-line path
      sol.tx = 6; sol.ty = 2;

      // Build dynamic walkable: sol's tile (6,2) is blocked
      const dynWalkable = engine._buildDynamicWalkable(maple);

      const blockerBlocked = dynWalkable[sol.ty]?.[sol.tx] === false;

      // moveTo goal (12, 2) — A* must route around (6,2)
      const success = maple.moveTo(12, 2, dynWalkable);

      if (!success) {
        return { success, blockerBlocked, blockerOnPath: false, pathLength: 0, path: [] };
      }

      const blockerKey = `${sol.ty}_${sol.tx}`;
      const pathKeys   = maple.path.map(s => `${s.ty}_${s.tx}`);
      const blockerOnPath = pathKeys.includes(blockerKey);

      return {
        success,
        blockerBlocked,
        blockerOnPath,
        pathLength: maple.path.length,
        // First few steps for debugging
        pathStart: maple.path.slice(0, 5),
      };
    });

    console.log('moveTo dynamic-walkable result:', JSON.stringify(result));

    expect(result.blockerBlocked,
      'Sol\'s tile should be marked blocked in the dynamic walkable grid'
    ).toBe(true);

    expect(result.success,
      'moveTo should find an alternative path even with blocker at (6,2)'
    ).toBe(true);

    expect(result.blockerOnPath,
      `Path must not route through blocker tile (6,2). Path: ${JSON.stringify(result.pathStart)}`
    ).toBe(false);

    expect(result.pathLength,
      'Path must have at least one step'
    ).toBeGreaterThan(0);
  });

  // ── TEST 4: Deadlock escape after 3 wander failures ───────────────────────

  test('_failedMoveCount resets to 0 after third consecutive wander failure (deadlock escape)', async ({ page }) => {
